import { useState, useEffect } from "react";
import { getApiBase } from '../utils/platform';

/**
 * Kill Switch Modal — Emergency trading halt with confirmation.
 * Uses POST /api/control/kill-switch to activate, DELETE to deactivate.
 */
export default function KillSwitchModal({ isOpen, onClose }) {
  const [status, setStatus] = useState(null);
  const [reason, setReason] = useState("");
  const [loading, setLoading] = useState(false);
  const [confirmDeactivate, setConfirmDeactivate] = useState(false);

  useEffect(() => {
    if (isOpen) {
      fetch(`${getApiBase()}/control/kill-switch`)
        .then((r) => r.json())
        .then(setStatus)
        .catch(() => setStatus(null));
    }
  }, [isOpen]);

  const activate = async () => {
    if (!reason.trim()) return;
    setLoading(true);
    try {
      const token = localStorage.getItem("access_token");
      const r = await fetch(`${getApiBase()}/control/kill-switch`, {
        method: "POST",
        headers: { "Content-Type": "application/json", Authorization: `Bearer ${token}` },
        body: JSON.stringify({ reason, initiator: "ui", flatten_positions: true, cancel_orders: true }),
      });
      const data = await r.json();
      setStatus({ active: true, ...data });
      setReason("");
    } catch (e) {
      console.error("Kill switch activation failed:", e);
    }
    setLoading(false);
  };

  const deactivate = async () => {
    setLoading(true);
    try {
      const token = localStorage.getItem("access_token");
      await fetch(`${getApiBase()}/control/kill-switch?confirm=true&by=ui`, {
        method: "DELETE",
        headers: { Authorization: `Bearer ${token}` },
      });
      setStatus({ active: false });
      setConfirmDeactivate(false);
    } catch (e) {
      console.error("Kill switch deactivation failed:", e);
    }
    setLoading(false);
  };

  if (!isOpen) return null;

  const isActive = status?.active;

  return (
    <div
      role="dialog"
      aria-modal="true"
      aria-labelledby="kill-switch-title"
      style={{
        position: "fixed", inset: 0, zIndex: 9999,
        display: "flex", alignItems: "center", justifyContent: "center",
        background: "rgba(0,0,0,0.8)", backdropFilter: "blur(4px)",
      }}
      onClick={onClose}
    >
      <div style={{
        background: "#161B22", border: `2px solid ${isActive ? "#EF4444" : "#30363D"}`,
        borderRadius: 14, padding: 32, maxWidth: 480, width: "90%",
        boxShadow: isActive ? "0 0 40px rgba(248,81,73,0.3)" : "0 8px 32px rgba(0,0,0,0.5)",
      }} onClick={(e) => e.stopPropagation()}>

        <div style={{ display: "flex", alignItems: "center", gap: 12, marginBottom: 24 }}>
          <span style={{ fontSize: 28 }}>{isActive ? "🔴" : "⚪"}</span>
          <div>
            <h2 id="kill-switch-title" style={{ color: "#E6EDF3", margin: 0, fontSize: 22, fontFamily: "Plus Jakarta Sans, sans-serif" }}>
              Emergency Kill Switch
            </h2>
            <p style={{ color: "#8B949E", margin: 0, fontSize: 13 }}>
              {isActive ? `Active since ${status.activated_at || "unknown"}` : "All systems trading normally"}
            </p>
          </div>
        </div>

        {isActive ? (
          /* ── Deactivate flow ── */
          <div>
            <div role="alert" style={{
              background: "#1C0A0A", border: "1px solid #EF4444", borderRadius: 10,
              padding: 16, marginBottom: 20,
            }}>
              <p style={{ color: "#EF4444", margin: 0, fontWeight: 600 }}>Kill switch is ACTIVE</p>
              <p style={{ color: "#8B949E", margin: "8px 0 0", fontSize: 13 }}>
                Reason: {status.reason || "No reason provided"}<br />
                By: {status.initiator || "unknown"}
              </p>
            </div>

            {!confirmDeactivate ? (
              <button onClick={() => setConfirmDeactivate(true)} style={{
                width: "100%", padding: "12px 20px", borderRadius: 10,
                background: "#238636", border: "none", color: "#fff",
                fontSize: 14, fontWeight: 600, cursor: "pointer",
              }}>
                Re-enable Trading
              </button>
            ) : (
              <div>
                <p style={{ color: "#F59E0B", fontSize: 14, marginBottom: 12 }}>
                  Are you sure? This will allow all bots to resume trading.
                </p>
                <div style={{ display: "flex", gap: 12 }}>
                  <button onClick={deactivate} disabled={loading} aria-busy={loading} style={{
                    flex: 1, padding: "12px 20px", borderRadius: 10,
                    background: "#238636", border: "none", color: "#fff",
                    fontSize: 14, fontWeight: 600, cursor: "pointer",
                    opacity: loading ? 0.5 : 1,
                  }}>
                    {loading ? "Deactivating..." : "Confirm Re-enable"}
                  </button>
                  <button onClick={() => setConfirmDeactivate(false)} style={{
                    flex: 1, padding: "12px 20px", borderRadius: 10,
                    background: "#21262D", border: "1px solid #30363D", color: "#8B949E",
                    fontSize: 14, cursor: "pointer",
                  }}>
                    Cancel
                  </button>
                </div>
              </div>
            )}
          </div>
        ) : (
          /* ── Activate flow ── */
          <div>
            <p style={{ color: "#8B949E", fontSize: 14, marginBottom: 16 }}>
              This will immediately:<br />
              • Cancel all open orders across all bots<br />
              • Flatten all positions (market orders)<br />
              • Block all new order submissions
            </p>

            <input
              value={reason}
              onChange={(e) => setReason(e.target.value)}
              placeholder="Reason for emergency stop..."
              aria-label="Reason for emergency stop"
              aria-required="true"
              style={{
                width: "100%", padding: "10px 14px", borderRadius: 10,
                background: "#0D1117", border: "1px solid #30363D", color: "#E6EDF3",
                fontSize: 14, marginBottom: 16, boxSizing: "border-box",
                fontFamily: "Plus Jakarta Sans, sans-serif",
              }}
            />

            <button
              onClick={activate}
              disabled={!reason.trim() || loading}
              aria-busy={loading}
              style={{
                width: "100%", padding: "14px 20px", borderRadius: 10,
                background: reason.trim() ? "#DA3633" : "#21262D",
                border: reason.trim() ? "2px solid #EF4444" : "1px solid #30363D",
                color: reason.trim() ? "#fff" : "#8B949E",
                fontSize: 16, fontWeight: 700, cursor: reason.trim() ? "pointer" : "not-allowed",
                opacity: loading ? 0.5 : 1,
                textTransform: "uppercase", letterSpacing: 1,
              }}
            >
              {loading ? "ACTIVATING..." : "ACTIVATE KILL SWITCH"}
            </button>
          </div>
        )}

        <button onClick={onClose} aria-label="Close dialog" style={{
          position: "absolute", top: 12, right: 16, background: "none",
          border: "none", color: "#8B949E", fontSize: 22, cursor: "pointer",
        }}>×</button>
      </div>
    </div>
  );
}
